BGP_路由:
!
bgp {{ local_as }}
 router-id {{ bgp_router_id }}
 balance {{ bgp_max_paths }}
 !
 peer {{ peer_ip_1 }} as-number {{ neighbor_as_1 }}
 peer {{ peer_ip_1 }} description {{ peer_desc_1 }}
 peer {{ peer_ip_1 }} connect-interface LoopBack0
 !
 peer {{ peer_ip_2 }} as-number {{ neighbor_as_2 }}
 peer {{ peer_ip_2 }} description {{ peer_desc_2 }}
 peer {{ peer_ip_2 }} connect-interface LoopBack0
 !
 address-family ipv4 unicast
  network {{ bgp_network_1 }} {{ bgp_mask_1 }}
  network {{ bgp_network_2 }} {{ bgp_mask_2 }}
  peer {{ peer_ip_1 }} enable
  peer {{ peer_ip_2 }} enable
!
